mapper.select:
SELECT co.id, co.order_id, co.product_id, co.product_name, co.shop_id, co.shop_name, co.order_amount, co.actual_amount, co.settle_amount, co.estimate_service_fee, co.effective_service_fee, co.estimate_tech_service_fee, co.effective_tech_service_fee, co.colonel_buyin_id, co.colonel_activity_id, co.settle_colonel_commission, co.settle_colonel_tech_service_fee, co.second_colonel_buyin_id, co.second_colonel_activity_id, co.settle_second_colonel_commission, co.flow_point, co.phase_id, co.order_status, co.order_type, co.settle_time, co.cursor, co.pick_source, co.channel_user_id, co.channel_user_name, co.channel_dept_id, co.user_id, co.dept_id, co.colonel_user_id, co.colonel_user_name, co.promotion_link_id, co.product_title, COALESCE( NULLIF(co.product_pic, ''), NULLIF(co.extra_data ->> 'product_img', ''), NULLIF(co.extra_data ->> 'productImg', ''), NULLIF(co.extra_data ->> 'product_pic', ''), NULLIF(co.extra_data ->> 'productPic', '') ) AS product_pic, CASE WHEN COALESCE( NULLIF(co.extra_data ->> 'item_num', ''), NULLIF(co.extra_data ->> 'itemNum', ''), NULLIF(co.extra_data ->> 'quantity', ''), NULLIF(co.extra_data ->> 'productQuantity', ''), NULLIF(co.extra_data ->> 'goods_num', ''), NULLIF(co.extra_data ->> 'goodsNum', '') ) ~ '^[0-9]+$' THEN COALESCE( NULLIF(co.extra_data ->> 'item_num', ''), NULLIF(co.extra_data ->> 'itemNum', ''), NULLIF(co.extra_data ->> 'quantity', ''), NULLIF(co.extra_data ->> 'productQuantity', ''), NULLIF(co.extra_data ->> 'goods_num', ''), NULLIF(co.extra_data ->> 'goodsNum', '') )::INTEGER ELSE NULL END AS item_num, CASE WHEN COALESCE( NULLIF(co.extra_data ->> 'commission_rate', ''), NULLIF(co.extra_data ->> 'commissionRate', ''), NULLIF(co.extra_data ->> 'cos_ratio', ''), NULLIF(co.extra_data ->> 'cosRatio', '') ) ~ '^[0-9]+([.][0-9]+)?$' THEN COALESCE( NULLIF(co.extra_data ->> 'commission_rate', ''), NULLIF(co.extra_data ->> 'commissionRate', ''), NULLIF(co.extra_data ->> 'cos_ratio', ''), NULLIF(co.extra_data ->> 'cosRatio', '') )::NUMERIC ELSE NULL END AS commission_rate, CASE WHEN COALESCE( NULLIF(co.extra_data ->> 'service_fee_rate', ''), NULLIF(co.extra_data ->> 'serviceFeeRate', ''), NULLIF(co.extra_data ->> 'service_rate', ''), NULLIF(co.extra_data ->> 'serviceRate', '') ) ~ '^[0-9]+([.][0-9]+)?$' THEN COALESCE( NULLIF(co.extra_data ->> 'service_fee_rate', ''), NULLIF(co.extra_data ->> 'serviceFeeRate', ''), NULLIF(co.extra_data ->> 'service_rate', ''), NULLIF(co.extra_data ->> 'serviceRate', '') )::NUMERIC ELSE NULL END AS service_fee_rate, co.talent_name, co.talent_id, co.pay_time, co.order_create_time, co.attribution_status, co.attribution_remark, co.create_time, co.update_time, co.deleted FROM colonelsettlement_order co WHERE co.deleted = 0
AND ${ew.sqlSegment}
ORDER BY co.create_time DESC
